using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using System.Text;

public class ReportController : Controller
{
    private readonly ILogger<ReportController> _logger;

    public ReportController(ILogger<ReportController> logger)
    {
        _logger = logger;
    }

    // Was: btnExport_Click with Response.Clear/Write/End
    // Now: Return a FileResult — no need to manually manage the response stream.
    // The framework handles Content-Disposition, Content-Type, and completing the response.
    [HttpPost]
    public IActionResult Export()
    {
        var data = GenerateReport();

        return File(
            Encoding.UTF8.GetBytes(data),
            "text/csv",
            "report.csv"
        );
    }

    // Was: btnRedirect_Click with Response.Redirect(url, true) and ThreadAbortException catch
    // Now: Return IActionResult — RedirectResult or other results replace Response.Redirect.
    // No ThreadAbortException exists in .NET 8; cooperative cancellation via
    // HttpContext.RequestAborted replaces the old abort model.
    [HttpPost]
    public IActionResult ProcessAndRedirect()
    {
        if (!User.Identity?.IsAuthenticated ?? true)
        {
            return Redirect("/login");
        }

        try
        {
            ProcessRequest();
            return Redirect("/success");
        }
        // ThreadAbortException catch block removed — it is never thrown in .NET 8.
        // OperationCanceledException replaces it for cancellation scenarios.
        catch (OperationCanceledException)
        {
            // Client disconnected mid-request; nothing to redirect to.
            // Log and return an empty result.
            _logger.LogInformation("Request cancelled by client");
            return StatusCode(499); // Client Closed Request
        }
        catch (Exception ex)
        {
            LogError(ex);
            return Redirect("/error");
        }
    }

    // If ProcessRequest is long-running, accept the request-aborted token
    // so work stops promptly when the client disconnects.
    private void ProcessRequest()
    {
        var token = HttpContext.RequestAborted;
        // Pass token through the call chain:
        // e.g., _service.DoWork(token);
        token.ThrowIfCancellationRequested();
    }

    private string GenerateReport() => "col1,col2\nval1,val2";

    private void LogError(Exception ex) => _logger.LogError(ex, "Request processing failed");
}

